//DSLooper
testRunner.testCase.testSuite.project.testSuites["@Utils"].testCases["@Looper"].testSteps["@DSLooper"].run(testRunner, context);
return;

//cleanUp project props
testRunner.testCase.testSuite.project.testSuites["@Utils"].testCases["@CleanUp"].testSteps["@CleanUpProjectProps"].run(testRunner, context);
//get testRunId for test
testRunner.testCase.testSuite.project.testSuites["@Utils"].testCases["@GetData"].testSteps["@GetTestRunId"].run(testRunner, context);

//get ds values and set as project props
def inputProps = testRunner.testCase.testSteps["InputProps"];

for (prop in inputProps.getPropertyList()) {

	def propName = prop.getName();
	def propVal = prop.getValue();
	testRunner.testCase.testSuite.project.setPropertyValue(propName, propVal);
}

//run testSuite Execution
def project = testRunner.testCase.testSuite.project;
def runner = project.testSuites['Execution'].run(null, true);

runner.waitUntilFinished();

//DSLoop
testRunner.testCase.testSuite.project.testSuites["@Utils"].testCases["@Looper"].testSteps["@DSLoop"].run(testRunner, context);
return;

import com.eviware.soapui.support.XmlHolder;
import jxl.*;
import jxl.write.*;

def projRoot = context.expand('${projectDir}');
def env2test = context.expand('${#Project#env2test}');
def DS = testRunner.testCase.testSteps['DataSources'].getPropertyValue("DSInput");
def DSPath;

if (DS.startsWith("DS_envConfig")) {

	DSPath = projRoot + "/01_DataSources/" + DS + ".xls";
	testRunner.testCase.setPropertyValue("DSPath", DSPath);
}
else {

	DSPath = projRoot + "/01_DataSources/" + DS + "_" + env2test + ".xls";
	testRunner.testCase.setPropertyValue("DSPath", DSPath);
}

def Workbook wb = Workbook.getWorkbook(new File(DSPath));
def Sheet sh = wb.getSheet(0);

def rowsCount= sh.getRows().toInteger();
def colsCount = sh.getColumns().toInteger();

if(rowsCount == 1) {

	testRunner.fail("DataSource is empty");
	log.info "DataSource is empty - testCase run was canceled";
}
else {

	def inputProps = testRunner.testCase.getTestStepByName("InputProps");
	def looperProps = testRunner.testCase.getTestStepByName("LooperProps");
	looperProps.setPropertyValue("RowsCount", rowsCount.toString());
	actualRow = looperProps.getPropertyValue("ActualRow").toString();
	actualRow = actualRow.toInteger();

	def nextRow;
	if(actualRow > rowsCount-2 ) {

		nextRow = "1";
		testRunner.testCase.setPropertyValue("nextRow", nextRow);
	}
	else {

		nextRow = actualRow + 1;
		nextRow = nextRow.toString();
		testRunner.testCase.setPropertyValue("nextRow", nextRow);
	}

	nextRow = context.expand('${#TestCase#nextRow}');

	int i = 1;
	for(int j = 0; j < colsCount; j++) {

		headerCol = i.toString();
		//log.info headerCol;
		Cell headerCol = sh.getCell(j,0);
		header = headerCol.getContents();
		Cell cell = sh.getCell(j, actualRow);
		field = cell.getContents();
		inputProps.setPropertyValue(header, field);
		i++
	}

	wb.close();

	looperProps.setPropertyValue("ActualRow", nextRow.toString());
	nextRow++;
	log.info "DataSource = " + DS + ", actual row = ${(actualRow)} of ${(rowsCount)-1}";
 	log.info "*******************************************************************************************************************";	
	looperProps.setPropertyValue("NextRow", nextRow.toString());
	//looperProps.setPropertyValue("LoopsCount", nextRow.toString());

	if (actualRow == rowsCount-1) {

		looperProps.setPropertyValue("StopLoop", "StopLoop");
	}
	else if (actualRow==0) {

		def runner = new com.eviware.soapui.impl.wsdl.testcase.WsdlTestCaseRunner(testRunner.testCase, null);
		looperProps.setPropertyValue("StopLoop", "NextLoop");
	}
	else {

		looperProps.setPropertyValue("StopLoop", "NextLoop");
	}
}

def looperProps = testRunner.testCase.getTestStepByName("LooperProps");
def stopLoop = looperProps.getPropertyValue("StopLoop");

if (stopLoop.toString() == "StopLoop") {

	log.info ("End of rows  in dataSource - stop loop");
	log.info "******************************************************************************************************************";
}
else {

	testRunner.gotoStepByName("DSLooper");
}

import org.apache.commons.io.FileUtils;

//get project root path
def projRoot = context.expand('${projectDir}');

//get actual environment
def env2test = context.expand('${#Project#env2test}');

//get call execution dateTime
def reqExecDateTime = new java.text.SimpleDateFormat("yyyy-MM-dd HH:mm:SS").format(new Date());
log.info "reqExecDateTime = " + reqExecDateTime;

//get call step name
def stepName = testRunner.testCase.getTestStepAt(context.getCurrentStepIndex()).getLabel();
log.info "stepName = " + stepName;

def reqCorrelationId = context.expand('${#TestCase#reqCorrelationId}');
log.info "reqCorrelationId = " + reqCorrelationId;

//create folder for req/rsp if not exist
File directory = new File(projRoot + "/03_Requests_Responses/" + env2test);
if (!directory.exists()) {

	directory.mkdir();	
}

def response = context.expand( '${${#TestCase#stepName}#Response}' );
def rspStatusCode;
//get random string as file unique identificator
def randStr = org.apache.commons.lang.RandomStringUtils.random(10, true, true);
testRunner.testCase.setPropertyValue("randStr", randStr);
def rspTimeTaken;

if (!response.isEmpty()) {

	//get response http status code
	def rspStatus = context.testCase.testSteps[stepName].testRequest.response.responseHeaders["#status#"];
	rspStatusCode = (rspStatus =~ "[1-5]\\d\\d")[0];
	testRunner.testCase.setPropertyValue("rspStatusCode", rspStatusCode);
	log.info "rspStatusCode = " + rspStatusCode;

	//get response time
	rspTimeTaken = testRunner.testCase.testSteps[stepName].testRequest.response.timeTaken;
	log.info "rspTimeTaken = " + rspTimeTaken + "ms";

	//get raw request/response and create as txt file
	if(!rspStatusCode.startsWith("20")) {

		//get time dateTime for req/rsp name prefix
		def reqExecDateTimeForFileName = new java.text.SimpleDateFormat("yyyyMMdd_HHmmSS").format(new Date());

		//get time testVariantId for req/rsp name prefix
		def testVariantId = context.expand('${InputProps#testVariantId}')

		//get call url and method
		def method = context.testCase.testSteps[stepName].getHttpRequest().getMethod().toString();
		def url = context.testCase.testSteps[stepName].getHttpRequest().getEndpoint().toString()

		//get request headers
		def requestHeaders = context.testCase.testSteps[stepName].getHttpRequest().messageExchange.getRequestHeaders().toString()
		//get request
		def request = context.expand( '${${#TestCase#stepName}#Request}' );
		//create rawRequest
		def rawRequest = method + " " + url + "\r\n\r\n" + requestHeaders + "\r\n" + request;
		testRunner.testCase.setPropertyValue("rawRequest", rawRequest);

		//get response headers
		def responseHeaders = context.testCase.testSteps[stepName].testRequest.response.responseHeaders.toString();
		//get response
		response = context.expand( '${${#TestCase#stepName}#Response}' );
		log.info response;
		//create rawResponse
		def rawResponse = responseHeaders + "\r\n" + response;
		testRunner.testCase.setPropertyValue("rawResponse", rawResponse);

		//create raw req/rsp property 
		def reqRspRaw = "ExecDateTime = " + reqExecDateTimeForFileName + "\r\n\r\n" + "RAW REQUEST" + "\r\n\r\n" + rawRequest + 

		"\r\n\r\n" + 
		"=================================================================================================================================================================================" +
		"\r\n\r\n" + 
		"RAW RESPONSE" + "\r\n\r\n" + rawResponse;

		//create file with raw req/rsp
		def reqRspRawFile = new File(projRoot + "/03_Requests_Responses/" + env2test + "/" + stepName + "_req_rsp" + "(" + randStr + ").txt").write(reqRspRaw);
	}
}
else {

	log.info "rspStatusCode is not available - set Timmed out";
	testRunner.testCase.setPropertyValue("rspStatusCode", "TimedOut");

	//get time dateTime for req/rsp name prefix
	def reqExecDateTimeForFileName = new java.text.SimpleDateFormat("yyyyMMdd_HHmmSS").format(new Date());

	//get time testVariantId for req/rsp name prefix
	def testVariantId = context.expand('${InputProps#testVariantId}')

	//get call url and method
	def method = context.testCase.testSteps[stepName].getHttpRequest().getMethod().toString();
	def url = context.testCase.testSteps[stepName].getHttpRequest().getEndpoint().toString()

	//get request headers
	def requestHeaders = context.testCase.testSteps[stepName].getHttpRequest().getRequestHeaders().toString()
	//get request
	def request = context.expand( '${${#TestCase#stepName}#Request}' );
	//create rawRequest
	def rawRequest = method + " " + url + "\r\n\r\n" + requestHeaders + "\r\n" + request;
	testRunner.testCase.setPropertyValue("rawRequest", rawRequest);

	//create raw req/rsp property 
	def reqRspRaw = "ExecDateTime = " + reqExecDateTimeForFileName + "\r\n\r\n" + "RAW REQUEST" + "\r\n\r\n" + rawRequest + 

	"\r\n\r\n" + 
	"=================================================================================================================================================================================" +
	"\r\n\r\n" + 
	"RAW RESPONSE" + "\r\n\r\n" + "Not available due to time out";

	//create file with raw req/rsp
	def reqRspRawFile = new File(projRoot + "/03_Requests_Responses/" + env2test + "/" + stepName + "_req_rsp" + "(" + randStr + ").txt").write(reqRspRaw);
}

//check assertion status
testRunner.testCase.setPropertyValue("rspAssertsStatus", "1");

obj = context.testCase.getTestStepByName(stepName);
assertions = obj.getAssertionList();
assertions.each { 

	log.info(it.name + " - " + it.status);
	status = (it.status).toString();

	//assert status is failed or unknown set assert status as failed
	if(status.startsWith("FAIL")) {

		log.info "ASSERTS FAILED";
		testRunner.testCase.setPropertyValue("rspAssertsStatus", "-1");
	}
}

