import com.eviware.soapui.support.XmlHolder;
import org.apache.commons.io.FileUtils;
import jxl.*;
import jxl.write.*;

def projRoot = context.expand('${projectDir}');
def env2test = context.expand('${#Project#env2test}');
def DS = testRunner.testCase.testSteps['DataSources'].getPropertyValue("DSOutput");
def DSPath = projRoot + "/02_Results/" + DS +  "_" + env2test + ".xls";

def outputProps = testRunner.testCase.testSteps["OutputProps"];
def outputPropsCount = outputProps.getPropertyCount();

if (outputPropsCount > 0) {

	Workbook wb = Workbook.getWorkbook(new File(DSPath));
	WritableWorkbook wb1 = Workbook.createWorkbook(new File(DSPath), wb);  
	WritableSheet sh = wb1.getSheet(0);
	Sheet sh1 = wb1.getSheet(0);

	int i = 0;
	int j = 1;
	int k = sh1.getRows();

	for (prop in outputProps.getPropertyList()) {

		def headerCol = prop.getName();
		Label header = new Label(i, 0, headerCol);
		sh.addCell(header);
		def val = prop.getValue();
		Label value = new Label(i, k, val);
		sh.addCell(value);
		i++
	}
	wb1.write();
	wb1.close();
}
else {

	log.info("No properties");
}

def browserPath = testRunner.testCase.testSuite.project.testSuites["Runner"].testCases["Runner"].testSteps["InputProps"].getPropertyValue("browserPath").replace("\\", "\\\\");
def reqUrl =context.expand('${InputProps#reqUrl}');

def ProcessBuilder pb = new ProcessBuilder(browserPath, reqUrl);
pb.start();

return;

def randNumeric = org.apache.commons.lang.RandomStringUtils.randomNumeric(24);
def reqCorrelationId = "c" + randNumeric;
testRunner.testCase.setPropertyValue("reqCorrelationId", reqCorrelationId);

import java.util.Calendar;
import java.text.SimpleDateFormat;

def inputProps = testRunner.testCase.testSteps["InputProps"];

for (prop in inputProps.getPropertyList()) {

	def propName = prop.getName();
	def propValue = prop.getValue();

	if(propName.contains("(d)") || propName.contains("(dt)")) {

		def dsPeriod = propValue.substring(0,1);
		def dsOperator;
		def dsValue;
		int dsIntValue;

		if (propValue.length() > 1) {
			dsOperator = propValue.substring(1,2);
			dsValue = propValue.substring(2);
			dsIntValue = Integer.parseInt(dsValue);
		}
		SimpleDateFormat sdf;
		if(propName.contains("(d)")) {

			sdf = new SimpleDateFormat("yyyy-MM-dd");
		}
		if(propName.contains("(dt)")) {

			sdf = new SimpleDateFormat("yyyy-MM-dd HH:mm:SS");
		}
		Date dt = new Date();
		Calendar cal = Calendar.getInstance();
		cal.setTime(dt);
		Map periodMap = [D: "DATE", W: "WEEK_OF_MONTH", M: "MONTH", Y: "YEAR"];
		def periodMapVal = periodMap[dsPeriod];

		if(dsPeriod.equals(dsPeriod)) {

			if(dsOperator.equals("-")) {

				cal.add(Calendar."${periodMapVal}", - dsIntValue);
			}
			else{

				cal.add(Calendar."${periodMapVal}", dsIntValue);
			}
		}
		def evalDate = sdf.format(cal.getTime());
		testRunner.testCase.testSteps['InputProps'].setPropertyValue(propName, evalDate);
		log.info propName + " = " + evalDate;
	}
}

import java.util.Random;

def String birthDateString = context.expand('${InputProps#dsBirthdate(d)}');
def gender = context.expand('${InputProps#dsGender}');

context.generatedRC = generateSimpleRC(birthDateString, gender);

def generateSimpleRC(birthDateString, gender) {

	def yearPartofRC = birthDateString.substring(2, 4);
	def monthPartofRC = birthDateString.substring(5, 7);

	if (gender.equals("F")) {

		int monthNumber = Integer.valueOf(monthPartofRC);
		monthPartofRC = String.valueOf(monthNumber + 50);
	}
	def dayPartofRC = birthDateString.substring(8);
	def parsedRCDateBase = yearPartofRC + monthPartofRC + dayPartofRC;

	def random = new Random();
	def int randomNumber = random.ints(100, (999 + 1)).findFirst().getAsInt();
	def String randomRCsuffixString = String.valueOf(randomNumber);
	def RCBaseString = parsedRCDateBase + randomRCsuffixString;

	int valueForModulo11Validation = Integer.valueOf(RCBaseString);

	def int modulo11 = valueForModulo11Validation % 11;
	def validationDigit;

	if (modulo11 == 10) {

		validationDigit = "0";
	} 
	else {

		validationDigit = String.valueOf(modulo11);
	}
	//log.info RCBaseString + validationDigit;
	testRunner.testCase.getTestStepByName("InputProps")setPropertyValue( "birthNumber", RCBaseString + validationDigit.toString());
}

